pdf.body:
Request for Quotation
Vendor's Name:
${record.custrecord_njt_pq_vendor}
${record.custrecord_njt_pq_vendor}
Phone: ${companyInformation.phone}
Quotation No
${record.custrecord_njt_pq_quotation_ref_no}
Quotation Date
${record.custrecord_njt_pq_date}
Valid Till Date
${record.duedate}
Payment Terms
${record.terms}
<#assign totalAmount = 0> <#assign totalVat = 0> <#assign grandTotal = 0>
Item UOM Quantity Rate Amount VAT Rate VAT Total
<#list record.recmachcustrecord_njt_pq_items_parent_link as item>
<#if item.custrecord_njt_pq_items_amount?has_content> <#assign totalAmount = totalAmount + item.custrecord_njt_pq_items_amount?number> </#if> <#if item.custrecord_njt_pq_items_taxamt?has_content> <#assign totalVat = totalVat + item.custrecord_njt_pq_items_taxamt?number> </#if> <#if item.custrecord_njt_pq_items_gross_amt?has_content> <#assign grandTotal = grandTotal + item.custrecord_njt_pq_items_gross_amt?number> </#if>
${item_index + 1}. ${item.custrecord_njt_pq_items_items}
${item.custrecord_njt_pq_items_units} ${item.custrecord_njt_pq_items_quantity}
${item.custrecord_njt_pq_items_rate?string["#,##0.00"]} ${item.custrecord_njt_pq_items_amount?string["#,##0.00"]}
${item.custrecord_njt_pq_items_taxrate}% ${item.custrecord_njt_pq_items_taxamt?string["#,##0.00"]}
${item.custrecord_njt_pq_items_gross_amt?string["#,##0.00"]}
</#list>
<#function numToWords n> <#assign units = ["", "One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine", "Ten", "Eleven", "Twelve", "Thirteen", "Fourteen", "Fifteen", "Sixteen", "Seventeen", "Eighteen", "Nineteen"]> <#assign tens = ["", "Ten", "Twenty", "Thirty", "Forty", "Fifty", "Sixty", "Seventy", "Eighty", "Ninety"]> <#if (n < 20)> <#return units[n]> <#elseif (n < 100)> <#return (tens[(n/10)?floor] + ((n%10 != 0)?string(" " + units[n%10], "")))> <#elseif (n < 1000)> <#return (units[(n/100)?floor] + " Hundred" + ((n%100 != 0)?string(" and " + numToWords(n%100), "")))> <#elseif (n < 1000000)> <#return (numToWords((n/1000)?floor) + " Thousand" + ((n%1000 != 0)?string(" " + numToWords(n%1000), "")))> <#elseif (n < 1000000000)> <#return (numToWords((n/1000000)?floor) + " Million" + ((n%1000000 != 0)?string(" " + numToWords(n%1000000), "")))> <#else> <#return ""> </#if> </#function>
<#assign wholePart = grandTotal?floor> <#assign decimalPart = ((grandTotal - wholePart) * 100)?round> <#assign words = ""> <#if wholePart == 0><#assign words = "Zero Dirhams"> <#else><#assign words = numToWords(wholePart) + " Dirhams"> </#if> <#if decimalPart gt 0><#assign words = words + " and " + numToWords(decimalPart) + " Fils"> </#if>
TERMS AND CONDITIONS
1.
2.
ADDITIONAL NOTES
1.
2.
3.
Amount AED ${record.custrecord_amount}
VAT AED ${record.custrecord_tax}
Total (AED) AED ${record.custrecord_total}
TOTAL (IN WORDS) :
${customData.totalWords} ONLY
